<?php require_once "config/database.php"; require_once "includes/session.php"; requireLogin();if(!isset($_SESSION['cart']))$_SESSION['cart']=[];if(isset($_POST['add_to_cart']))$_SESSION['cart'][$_POST['product_id']]=($_SESSION['cart'][$_POST['product_id']]??0)+intval($_POST['quantity']);if(isset($_GET['remove']))unset($_SESSION['cart'][$_GET['remove']]);if(isset($_POST['checkout'])){$total=0;foreach($_SESSION['cart'] as $pid=>$q){$s=$conn->prepare("SELECT * FROM products WHERE product_id=?");$s->execute([$pid]);$p=$s->fetch(PDO::FETCH_ASSOC);$total+=$p['price']*$q;}$conn->prepare("INSERT INTO orders(user_id,total_amount,payment_method) VALUES(?,?,?)")->execute([$_SESSION['user_id'],$total,$_POST['payment_method']]);$oid=$conn->lastInsertId();foreach($_SESSION['cart'] as $pid=>$q){$s=$conn->prepare("SELECT * FROM products WHERE product_id=?");$s->execute([$pid]);$p=$s->fetch(PDO::FETCH_ASSOC);$conn->prepare("INSERT INTO order_items(order_id,product_id,quantity,price) VALUES(?,?,?,?)")->execute([$oid,$pid,$q,$p['price']]);}$_SESSION['cart']=[];header("Location: tenant/dashboard.php");exit;}include "includes/header.php";?><div class="container"><h1 class="section-title">Cart</h1><div class="table-wrap"><table><tr><th>Product</th><th>Qty</th><th>Price</th><th>Total</th><th>Action</th></tr><?php $gt=0;foreach($_SESSION['cart'] as $pid=>$q):$s=$conn->prepare("SELECT * FROM products WHERE product_id=?");$s->execute([$pid]);$p=$s->fetch(PDO::FETCH_ASSOC);$lt=$p['price']*$q;$gt+=$lt;?><tr><td><?=e($p['product_name'])?></td><td><?=$q?></td><td>₱<?=number_format($p['price'],2)?></td><td>₱<?=number_format($lt,2)?></td><td><a class="btn danger" href="?remove=<?=$pid?>">Remove</a></td></tr><?php endforeach;?></table><h2>Total: ₱<?=number_format($gt,2)?></h2><?php if($gt>0):?><form method="POST"><select name="payment_method"><option>Cash</option><option>GCash</option><option>Bank Transfer</option></select><button name="checkout" class="btn gold">Checkout</button></form><?php endif;?></div></div><?php include "includes/footer.php";?>
